301→// ─── wasm-bindgen tests ──────────────────────────────────────────────────────
302→//
303→// Run with: wasm-pack test --node --features wasm
304→// These tests exercise the actual `#[wasm_bindgen]` surface through the
305→// wasm-bindgen-test harness (no browser required when using --node).
306→
307→#[cfg(test)]
308→mod wasm_tests {
309→    use super::*;
310→    use wasm_bindgen_test::wasm_bindgen_test;
311→
312→    // ── constants ───────────────────────────────────────────────────────────
313→
314→    /// `public_key_length()` must return 896.
315→    #[wasm_bindgen_test]
316→    fn wasm_public_key_length_is_896() {
317→        assert_eq!(public_key_length(), 896);
318→    }
319→
320→    /// `salt_length()` must return 40.
321→    #[wasm_bindgen_test]
322→    fn wasm_salt_length_is_40() {
323→        assert_eq!(salt_length(), 40);
324→    }
325→
326→    // ── verify ──────────────────────────────────────────────────────────────
327→
328→    /// `verify()` with wrong pk length returns an error.
329→    #[wasm_bindgen_test]
330→    fn wasm_verify_rejects_short_pk() {
331→        let short_pk = vec![0u8; 10];
332→        let result = verify(&short_pk, b"msg", b"sig");
333→        assert!(result.is_err(), "short pk must be rejected");
334→    }
335→
336→    /// `verify()` with correct pk length but invalid signature is rejected.
337→    #[wasm_bindgen_test]
338→    fn wasm_verify_rejects_invalid_signature() {
339→        let zero_pk = vec![0u8; PUBLIC_KEY_LEN];
340→        let bad_sig = vec![0xFF_u8; 50]; // bad header
341→        let result = verify(&zero_pk, b"msg", &bad_sig);
342→        assert!(result.is_err(), "invalid signature header must be rejected");
343→    }
344→
345→    // ── sign ────────────────────────────────────────────────────────────────
346→
347→    /// `sign()` with invalid sk length (not 4 * PUBLIC_KEY_LEN) must return an error.
348→    #[wasm_bindgen_test]
349→    fn wasm_sign_rejects_invalid_sk_length() {
350→        let short_sk = vec![0u8; 100];
351→        let result = sign(&short_sk, b"hello", &[0u8; SALT_LEN]);
352→        assert!(result.is_err(), "sign() must reject sk with wrong length");
353→    }
354→
355→    /// `sign()` with wrong salt length must return an error.
356→    #[wasm_bindgen_test]
357→    fn wasm_sign_rejects_invalid_salt_length() {
358→        // Use a dummy sk of the right byte length but invalid content
359→        let dummy_sk = vec![0u8; 4 * crate::falcon::PUBLIC_KEY_LEN];
360→        let wrong_salt = vec![0u8; 10]; // too short
361→        let result = sign(&dummy_sk, b"hello", &wrong_salt);
362→        assert!(result.is_err(), "sign() must reject salt with wrong length");
363→    }
364→
365→    /// `sign()` with a valid sk (from keygen) must return a JS object with
366→    /// `signature` (Uint8Array of SIGNATURE_LEN) and `salt` (Uint8Array of SALT_LEN).
367→    ///
368→    /// NOTE: this test requires a real keypair, so it exercises the full keygen → sign path.
369→    /// Key generation is slow; this test is intentionally scoped to a fast deterministic path.
370→    #[wasm_bindgen_test]
371→    fn wasm_sign_succeeds_with_valid_sk() {
372→        use crate::falcon::SIGNATURE_LEN;
373→
374→        let seed = [20u8; 32];
375→        let keypair = keygen(&seed).expect("keygen must succeed with 32-byte seed");
376→
377→        // Extract sk bytes from the keypair JsValue
378→        let sk_js =
379→            js_sys::Reflect::get(&keypair, &"sk".into()).expect("keypair must have sk property");
380→        let sk_arr = js_sys::Uint8Array::from(sk_js);
381→        let sk_bytes = sk_arr.to_vec();
382→
383→        let salt = [0u8; SALT_LEN];
384→        let result = sign(&sk_bytes, b"hello wasm sign", &salt);
385→        assert!(
386→            result.is_ok(),
387→            "sign() must succeed with valid sk: {:?}",
388→            result.err()
389→        );
390→
391→        let result_obj = result.unwrap();
392→
393→        // Must have a `signature` Uint8Array of length SIGNATURE_LEN
394→        let sig_js = js_sys::Reflect::get(&result_obj, &"signature".into())
395→            .expect("result must have `signature` property");
396→        let sig_arr = js_sys::Uint8Array::from(sig_js);
397→        assert_eq!(
398→            sig_arr.length() as usize,
399→            SIGNATURE_LEN,
400→            "signature must be SIGNATURE_LEN={} bytes",
401→            SIGNATURE_LEN
402→        );
403→
404→        // Must have a `salt` Uint8Array of length SALT_LEN
405→        let salt_js = js_sys::Reflect::get(&result_obj, &"salt".into())
406→            .expect("result must have `salt` property");
407→        let salt_arr = js_sys::Uint8Array::from(salt_js);
408→        assert_eq!(
409→            salt_arr.length() as usize,
410→            SALT_LEN,
411→            "salt must be SALT_LEN={} bytes",
412→            SALT_LEN
413→        );
414→
415→        // The embedded salt must match what we passed in
416→        let returned_salt = salt_arr.to_vec();
417→        assert_eq!(
418→            returned_salt,
419→            salt.to_vec(),
420→            "returned salt must match input salt"
421→        );
422→    }
423→
424→    // ── create_verification_hint ──────────────────────────────────────
425→
426→    #[wasm_bindgen_test]
427→    fn wasm_create_verification_hint_rejects_wrong_length() {
428→        let short = vec![0i32; 10];
429→        let correct = vec![0i32; 512];
430→        assert!(create_verification_hint(&short, &correct).is_err());
431→        assert!(create_verification_hint(&correct, &short).is_err());
432→    }
433→
434→    // ── pack_public_key_wasm ────────────────────────────────────────────
435→
436→    #[wasm_bindgen_test]
437→    fn wasm_pack_public_key_rejects_wrong_length() {
438→        let short = vec![0u16; 10];
439→        assert!(pack_public_key_wasm(&short).is_err());
440→    }
441→
442→    #[wasm_bindgen_test]
443→    fn wasm_pack_public_key_returns_29_slots() {
444→        let pk = vec![0u16; 512];
445→        let result = pack_public_key_wasm(&pk).expect("packing zeros must succeed");
446→        assert_eq!(result.len(), 29, "must produce exactly 29 felt252 slots");
447→        for slot in &result {
448→            assert!(slot.starts_with("0x"), "each slot must be 0x-prefixed hex");
449→        }
450→    }
451→
452→    // ── sign + verify roundtrip ─────────────────────────────────────────
453→
454→    /// `sign()` + `verify()` round-trip: a signature produced by `sign()` must
455→    /// pass `verify()` with the corresponding verifying key.
456→    #[wasm_bindgen_test]
457→    fn wasm_sign_verify_roundtrip() {
458→        let seed = [21u8; 32];
459→        let keypair = keygen(&seed).expect("keygen must succeed");
460→
461→        let sk_js = js_sys::Reflect::get(&keypair, &"sk".into()).expect("keypair must have sk");
462→        let vk_js = js_sys::Reflect::get(&keypair, &"vk".into()).expect("keypair must have vk");
463→
464→        let sk_bytes = js_sys::Uint8Array::from(sk_js).to_vec();
465→        let vk_bytes = js_sys::Uint8Array::from(vk_js).to_vec();
466→
467→        let message = b"wasm sign-verify roundtrip";
468→        let salt = [1u8; SALT_LEN];
469→
470→        let sign_result = sign(&sk_bytes, message, &salt).expect("sign must succeed with valid sk");
471→
472→        // Extract the full signature bytes
473→        let sig_js = js_sys::Reflect::get(&sign_result, &"signature".into())
474→            .expect("sign result must have signature");
475→        let sig_bytes = js_sys::Uint8Array::from(sig_js).to_vec();
476→
477→        let valid = verify(&vk_bytes, message, &sig_bytes)
478→            .expect("verify must not error on a valid signature");
479→
480→        assert!(valid, "signature produced by sign() must verify with vk");
481→    }
482→}
