  3→/**
  4→ * Create a verification hint for Cairo on-chain verification.
  5→ *
  6→ * Computes `INTT(NTT(s1) * pk_ntt)` — the mul_hint that allows
  7→ * Cairo to verify NTT products with 2 forward NTTs and 0 INTTs.
  8→ *
  9→ * Parameters:
 10→ * - `s1`: 512 signature coefficients (each in [0, 12289))
 11→ * - `pk_ntt`: 512 public key NTT coefficients (each in [0, 12289))
 12→ *
 13→ * Returns: Vec of 512 hint coefficients (returned as Uint16Array to JS).
 14→ * @param {Int32Array} s1
 15→ * @param {Int32Array} pk_ntt
 16→ * @returns {Uint16Array}
 17→ */
 18→export function create_verification_hint(s1, pk_ntt) {
 19→    const ptr0 = passArray32ToWasm0(s1, wasm.__wbindgen_malloc);
 20→    const len0 = WASM_VECTOR_LEN;
 21→    const ptr1 = passArray32ToWasm0(pk_ntt, wasm.__wbindgen_malloc);
 22→    const len1 = WASM_VECTOR_LEN;
 23→    const ret = wasm.create_verification_hint(ptr0, len0, ptr1, len1);
 24→    if (ret[3]) {
 25→        throw takeFromExternrefTable0(ret[2]);
 26→    }
 27→    var v3 = getArrayU16FromWasm0(ret[0], ret[1]).slice();
 28→    wasm.__wbindgen_free(ret[0], ret[1] * 2, 2);
 29→    return v3;
 30→}
