 32→/**
 33→ * Generate a new Falcon-512 keypair.
 34→ *
 35→ * Returns a JavaScript object with `sk` (secret key bytes) and `vk` (verifying key bytes).
 36→ *
 37→ * Note: Key generation is slow (~1-2 minutes) due to NTRU complexity.
 38→ * @param {Uint8Array} seed
 39→ * @returns {any}
 40→ */
 41→export function keygen(seed) {
 42→    const ptr0 = passArray8ToWasm0(seed, wasm.__wbindgen_malloc);
 43→    const len0 = WASM_VECTOR_LEN;
 44→    const ret = wasm.keygen(ptr0, len0);
 45→    if (ret[2]) {
 46→        throw takeFromExternrefTable0(ret[1]);
 47→    }
 48→    return takeFromExternrefTable0(ret[0]);
 49→}
