  1→//! WASM bindings for Falcon-512 signature scheme.
  2→//!
  3→//! This module provides JavaScript-friendly bindings for browser use.
  4→//! Currently uses SHAKE256 hash; Poseidon support will be added for Starknet.
  5→
  6→#![cfg(feature = "wasm")]
  7→
  8→use wasm_bindgen::prelude::*;
  9→
 10→use crate::falcon::{Falcon, SecretKey, Signature, VerifyingKey, PUBLIC_KEY_LEN};
 11→use crate::hash_to_point::Shake256Hash;
 12→use crate::hints::generate_mul_hint;
 13→use crate::packing::pack_public_key;
 14→use crate::SALT_LEN;
 15→
 16→/// Generate a new Falcon-512 keypair.
 17→///
 18→/// Returns a JavaScript object with `sk` (secret key bytes) and `vk` (verifying key bytes).
 19→///
 20→/// Note: Key generation is slow (~1-2 minutes) due to NTRU complexity.
 21→#[wasm_bindgen]
 22→pub fn keygen(seed: &[u8]) -> Result<JsValue, JsError> {
 23→    if seed.len() < 32 {
 24→        return Err(JsError::new("Seed must be at least 32 bytes"));
 25→    }
 26→
 27→    let (sk, vk) = Falcon::<Shake256Hash>::keygen_with_seed(seed);
 28→
 29→    let result = js_sys::Object::new();
 30→    js_sys::Reflect::set(
 31→        &result,
 32→        &"sk".into(),
 33→        &js_sys::Uint8Array::from(&sk.to_bytes()[..]),
 34→    )
 35→    .map_err(|e| JsError::new(&format!("Failed to set sk: {:?}", e)))?;
 36→    js_sys::Reflect::set(
 37→        &result,
 38→        &"vk".into(),
 39→        &js_sys::Uint8Array::from(&vk.to_bytes()[..]),
 40→    )
 41→    .map_err(|e| JsError::new(&format!("Failed to set vk: {:?}", e)))?;
 42→
 43→    Ok(result.into())
 44→}
 45→
 46→/// Sign a message with a secret key.
 47→///
 48→/// Parameters:
 49→/// - `sk_bytes`: The secret key bytes (serialized as 4 × 896 = 3584 bytes via `SecretKey::to_bytes`)
 50→/// - `message`: The message to sign
 51→/// - `salt`: A 40-byte random salt (must be exactly `SALT_LEN` bytes)
 52→///
 53→/// Returns a JavaScript object with:
 54→/// - `signature`: `Uint8Array` of 666 bytes (the full Falcon-512 signature)
 55→/// - `salt`: `Uint8Array` of 40 bytes (echo of the provided salt)
 56→///
 57→/// # Notes
 58→///
 59→/// The caller is responsible for generating a cryptographically random `salt` before
 60→/// calling this function. The same salt must not be reused for different messages.
 61→#[wasm_bindgen]
 62→pub fn sign(sk_bytes: &[u8], message: &[u8], salt: &[u8]) -> Result<JsValue, JsError> {
 63→    // Validate salt length
 64→    if salt.len() != SALT_LEN {
 65→        return Err(JsError::new(&format!(
 66→            "Invalid salt length: expected {SALT_LEN}, got {}",
 67→            salt.len()
 68→        )));
 69→    }
 70→    let salt_arr: [u8; SALT_LEN] = salt
 71→        .try_into()
 72→        .map_err(|_| JsError::new("Failed to convert salt to fixed-size array"))?;
 73→
 74→    // Deserialize the secret key (reconstructs b0_fft and LDL tree)
 75→    let sk = SecretKey::from_bytes(sk_bytes).map_err(|e| JsError::new(&e.to_string()))?;
 76→
 77→    // Sign the message with the provided salt
 78→    let sig = Falcon::<Shake256Hash>::sign_with_salt(&sk, message, &salt_arr);
 79→
 80→    // Build return object: { signature: Uint8Array, salt: Uint8Array }
 81→    let result = js_sys::Object::new();
 82→
 83→    js_sys::Reflect::set(
 84→        &result,
 85→        &"signature".into(),
 86→        &js_sys::Uint8Array::from(&sig.to_bytes()[..]),
 87→    )
 88→    .map_err(|e| JsError::new(&format!("Failed to set signature: {e:?}")))?;
 89→
 90→    js_sys::Reflect::set(
 91→        &result,
 92→        &"salt".into(),
 93→        &js_sys::Uint8Array::from(sig.salt().as_slice()),
 94→    )
 95→    .map_err(|e| JsError::new(&format!("Failed to set salt: {e:?}")))?;
 96→
 97→    Ok(result.into())
 98→}
 99→
100→/// Verify a signature.
101→///
102→/// Parameters:
103→/// - `vk_bytes`: The verifying key (public key) bytes
104→/// - `message`: The signed message
105→/// - `signature`: The signature bytes
106→///
107→/// Returns true if the signature is valid, false otherwise.
108→#[wasm_bindgen]
109→pub fn verify(vk_bytes: &[u8], message: &[u8], signature: &[u8]) -> Result<bool, JsError> {
110→    if vk_bytes.len() != PUBLIC_KEY_LEN {
111→        return Err(JsError::new(&format!(
112→            "Invalid verifying key length: expected {}, got {}",
113→            PUBLIC_KEY_LEN,
114→            vk_bytes.len()
115→        )));
116→    }
117→
118→    let vk_arr: [u8; PUBLIC_KEY_LEN] = vk_bytes
119→        .try_into()
120→        .map_err(|_| JsError::new("Invalid verifying key"))?;
121→
122→    let vk = VerifyingKey::from_bytes(&vk_arr).map_err(|e| JsError::new(&e.to_string()))?;
123→
124→    let sig = Signature::from_bytes(signature).map_err(|e| JsError::new(&e.to_string()))?;
125→
126→    Falcon::<Shake256Hash>::verify(&vk, message, &sig).map_err(|e| JsError::new(&e.to_string()))
127→}
128→
129→/// Get the public key length in bytes.
130→#[wasm_bindgen]
131→pub fn public_key_length() -> usize {
132→    PUBLIC_KEY_LEN
133→}
134→
135→/// Get the salt length in bytes.
136→#[wasm_bindgen]
137→pub fn salt_length() -> usize {
138→    SALT_LEN
139→}
140→
141→/// Create a verification hint for Cairo on-chain verification.
142→///
143→/// Computes `INTT(NTT(s1) * pk_ntt)` — the mul_hint that allows
144→/// Cairo to verify NTT products with 2 forward NTTs and 0 INTTs.
145→///
146→/// Parameters:
147→/// - `s1`: 512 signature coefficients (each in [0, 12289))
148→/// - `pk_ntt`: 512 public key NTT coefficients (each in [0, 12289))
149→///
150→/// Returns: Vec of 512 hint coefficients (returned as Uint16Array to JS).
151→#[wasm_bindgen]
152→pub fn create_verification_hint(s1: &[i32], pk_ntt: &[i32]) -> Result<Vec<u16>, JsError> {
153→    if s1.len() != 512 {
154→        return Err(JsError::new(&format!(
155→            "Invalid s1 length: expected 512, got {}",
156→            s1.len()
157→        )));
158→    }
159→    if pk_ntt.len() != 512 {
160→        return Err(JsError::new(&format!(
161→            "Invalid pk_ntt length: expected 512, got {}",
162→            pk_ntt.len()
163→        )));
164→    }
165→
166→    let s1_u16: Vec<u16> = s1.iter().map(|&v| v as u16).collect();
167→    let pk_u16: Vec<u16> = pk_ntt.iter().map(|&v| v as u16).collect();
168→
169→    Ok(generate_mul_hint(&s1_u16, &pk_u16))
170→}
171→
172→/// Pack a public key (512 Zq values) into 29 felt252 storage slots.
173→///
174→/// Uses base-Q Horner encoding: 18 values per felt252 (9 per u128 half).
175→/// This achieves a 17x calldata reduction (512 → 29 slots).
176→///
177→/// Parameters:
178→/// - `pk_ntt`: 512 public key NTT coefficients (each in [0, 12289))
179→///
180→/// Returns: Array of 29 hex strings, each representing a felt252.
181→#[wasm_bindgen]
182→pub fn pack_public_key_wasm(pk_ntt: &[u16]) -> Result<Vec<String>, JsError> {
183→    if pk_ntt.len() != 512 {
184→        return Err(JsError::new(&format!(
185→            "Invalid pk_ntt length: expected 512, got {}",
186→            pk_ntt.len()
187→        )));
188→    }
189→
190→    let packed = pack_public_key(pk_ntt);
191→    Ok(packed.iter().map(|f| format!("0x{}", f.to_hex())).collect())
192→}
193→
194→/// Sign a Starknet transaction hash using Falcon-512 with Poseidon hash-to-point.
195→///
196→/// This produces a signature in the format expected by the Cairo FalconAccount contract:
197→/// - 29 packed felt252 for s1 (signature polynomial)
198→/// - 29 packed felt252 for mul_hint (verification hint)
199→/// - 2 felt252 for the salt
200→/// - 1 felt252 for the salt length
201→/// Total: 61 felt252 elements.
202→///
203→/// Parameters:
204→/// - `sk_bytes`: Secret key bytes (serialized SecretKey)
205→/// - `tx_hash`: Transaction hash as hex string (felt252)
206→/// - `pk_ntt`: 512 public key NTT coefficients (each in [0, 12289))
207→///
208→/// Returns: Array of 61 hex strings, each representing a felt252.
209→#[wasm_bindgen]
210→pub fn sign_for_starknet(
211→    sk_bytes: &[u8],
212→    tx_hash: &str,
213→    pk_ntt: &[i32],
214→) -> Result<Vec<String>, JsError> {
215→    use crate::hash_to_point::HashToPoint;
216→    use crate::poseidon_hash::{Felt, PoseidonHashToPoint};
217→
218→    if pk_ntt.len() != 512 {
219→        return Err(JsError::new(&format!(
220→            "Invalid pk_ntt length: expected 512, got {}",
221→            pk_ntt.len()
222→        )));
223→    }
224→
225→    // 1. Deserialize secret key
226→    let sk = SecretKey::from_bytes(sk_bytes)
227→        .map_err(|e| JsError::new(&format!("Invalid secret key: {e}")))?;
228→
229→    // 2. Parse tx_hash as felt252
230→    let tx_hash_felt = Felt::from_hex(tx_hash)
231→        .map_err(|_| JsError::new(&format!("Invalid tx_hash hex: {tx_hash}")))?;
232→
233→    // 3. Generate random salt (2 felt252 values)
234→    let salt_bytes = getrandom_salt()?;
235→    let salt_felt0 = Felt::from_hex(&format!("0x{}", bytes_to_hex(&salt_bytes[..31])))
236→        .map_err(|_| JsError::new("Failed to create salt felt 0"))?;
237→    let salt_felt1 = Felt::from_hex(&format!("0x{}", bytes_to_hex(&salt_bytes[31..62])))
238→        .map_err(|_| JsError::new("Failed to create salt felt 1"))?;
239→    let salt = vec![salt_felt0, salt_felt1];
240→
241→    // 4. Compute msg_point = PoseidonHashToPoint([tx_hash], salt)
242→    let message = vec![tx_hash_felt];
243→    let msg_point = PoseidonHashToPoint::hash_to_point(&message, &salt);
244→
245→    // 5. Sign the prehashed point
246→    let sign_seed = {
247→        let mut s = [0u8; crate::SEED_LEN];
248→        s[..crate::SALT_LEN].copy_from_slice(&salt_bytes[..crate::SALT_LEN]);
249→        s
250→    };
251→    let (_s0, s1) = Falcon::<PoseidonHashToPoint>::sign_prehashed(&sk, &msg_point, &sign_seed);
252→
253→    // 6. Convert s1 to u16 (unsigned mod Q)
254→    let s1_u16: Vec<u16> = s1.iter().map(|&v| v.rem_euclid(crate::Q) as u16).collect();
255→
256→    // 7. Convert pk_ntt to u16
257→    let pk_u16: Vec<u16> = pk_ntt.iter().map(|&v| v.rem_euclid(crate::Q) as u16).collect();
258→
259→    // 8. Compute mul_hint = INTT(NTT(s1) * pk_ntt)
260→    let mul_hint = generate_mul_hint(&s1_u16, &pk_u16);
261→
262→    // 9. Pack s1 into 29 felt252
263→    let packed_s1 = pack_public_key(&s1_u16);
264→
265→    // 10. Pack mul_hint into 29 felt252
266→    let packed_hint = pack_public_key(&mul_hint);
267→
268→    // 11. Build output: [packed_s1(29), packed_hint(29), salt(2), salt_len(1)] = 61 elements
269→    let mut result: Vec<String> = Vec::with_capacity(61);
270→    for f in &packed_s1 {
271→        result.push(format!("0x{}", f.to_hex()));
272→    }
273→    for f in &packed_hint {
274→        result.push(format!("0x{}", f.to_hex()));
275→    }
276→    for f in &salt {
277→        result.push(format!("0x{}", f.to_hex()));
278→    }
279→    // Salt length as felt252
280→    result.push(format!("0x{:x}", salt.len()));
281→
282→    Ok(result)
283→}
284→
285→/// Convert bytes to hex string (avoids dependency on hex crate in non-dev builds).
286→fn bytes_to_hex(bytes: &[u8]) -> String {
287→    bytes.iter().map(|b| format!("{b:02x}")).collect()
288→}
289→
290→/// Generate random bytes for salt using getrandom.
291→fn getrandom_salt() -> Result<Vec<u8>, JsError> {
292→    let mut bytes = vec![0u8; 62]; // 2 * 31 bytes (each < felt252 max)
293→    getrandom::getrandom(&mut bytes)
294→        .map_err(|e| JsError::new(&format!("Failed to generate random salt: {e}")))?;
295→    // Ensure each 31-byte chunk is < P (Stark prime) by clearing top bit
296→    bytes[0] &= 0x07; // first chunk high byte
297→    bytes[31] &= 0x07; // second chunk high byte
298→    Ok(bytes)
299→}
