354→
355→    /// `sign()` with wrong salt length must return an error.
356→    #[wasm_bindgen_test]
357→    fn wasm_sign_rejects_invalid_salt_length() {
358→        // Use a dummy sk of the right byte length but invalid content
359→        let dummy_sk = vec![0u8; 4 * crate::falcon::PUBLIC_KEY_LEN];
360→        let wrong_salt = vec![0u8; 10]; // too short
361→        let result = sign(&dummy_sk, b"hello", &wrong_salt);
362→        assert!(result.is_err(), "sign() must reject salt with wrong length");
363→    }
364→
365→    /// `sign()` with a valid sk (from keygen) must return a JS object with
366→    /// `signature` (Uint8Array of SIGNATURE_LEN) and `salt` (Uint8Array of SALT_LEN).
367→    ///
368→    /// NOTE: this test requires a real keypair, so it exercises the full keygen → sign path.
369→    /// Key generation is slow; this test is intentionally scoped to a fast deterministic path.
370→    #[wasm_bindgen_test]
371→    fn wasm_sign_succeeds_with_valid_sk() {
372→        use crate::falcon::SIGNATURE_LEN;
373→
374→        let seed = [20u8; 32];
375→        let keypair = keygen(&seed).expect("keygen must succeed with 32-byte seed");
376→
377→        // Extract sk bytes from the keypair JsValue
378→        let sk_js =
379→            js_sys::Reflect::get(&keypair, &"sk".into()).expect("keypair must have sk property");
380→        let sk_arr = js_sys::Uint8Array::from(sk_js);
381→        let sk_bytes = sk_arr.to_vec();
382→
383→        let salt = [0u8; SALT_LEN];
384→        let result = sign(&sk_bytes, b"hello wasm sign", &salt);
385→        assert!(
386→            result.is_ok(),
387→            "sign() must succeed with valid sk: {:?}",
