417→        assert_eq!(
418→            returned_salt,
419→            salt.to_vec(),
420→            "returned salt must match input salt"
421→        );
422→    }
423→
424→    // ── create_verification_hint ──────────────────────────────────────
425→
426→    #[wasm_bindgen_test]
427→    fn wasm_create_verification_hint_rejects_wrong_length() {
428→        let short = vec![0i32; 10];
