471→
472→        // Extract the full signature bytes
473→        let sig_js = js_sys::Reflect::get(&sign_result, &"signature".into())
474→            .expect("sign result must have signature");
475→        let sig_bytes = js_sys::Uint8Array::from(sig_js).to_vec();
